import React from "react";

const Hero = () => {
  return (
    <section style={{ padding: "50px", textAlign: "center" }}>
      <h1>Welcome to Our Business</h1>
      <p>We provide the best services for you</p>
      <button>Contact Us</button>
    </section>
  );
};

export default Hero;
